/**
 * Facts 持久化层
 * 通过 IPC 调用主进程的 yamlService，读写 facts/*.yaml 文件
 * 与命令行工具共用同一数据源
 */

export interface Fact {
  id: string
  type: 'power' | 'item' | 'relation' | 'foreshadow'
  subject: string
  object: string
  content: string
  chapterStart: number
  chapterEnd: number
  createdAt: number
  confidence?: number
}

class FactsStore {
  private projectRoot: string | null = null

  async setProjectRoot(root: string): Promise<void> {
    if (!root || typeof root !== 'string') {
      throw new Error('无效的项目根路径')
    }
    this.projectRoot = root
  }

  private factsDir(): string {
    if (!this.projectRoot) throw new Error('未设置项目根路径')
    return `${this.projectRoot}/facts`
  }

  // ─── 读取 facts（通过 IPC 调用主进程 js-yaml） ─────────────────────────────

  async loadCharactersFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/characters_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch (e) {
      console.error('loadCharactersFacts 失败:', e)
    }
    return {}
  }

  async loadPlotFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/plot_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch (e) {
      console.error('loadPlotFacts 失败:', e)
    }
    return {}
  }

  async loadSettingsFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/settings_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch (e) {
      console.error('loadSettingsFacts 失败:', e)
    }
    return {}
  }

  // ─── 写入 facts（通过 IPC 调用主进程 js-yaml） ─────────────────────────────

  async appendFacts(facts: Array<{
    type: string
    subject: string
    object?: string
    content: string
    chapterStart: number
    chapterEnd: number
    confidence: number
  }>): Promise<{ success: boolean; error?: string }> {
    try {
      if (!this.projectRoot) {
        return { success: false, error: '未设置项目根路径' }
      }

      const charFacts = (await this.loadCharactersFacts()) as Record<string, Record<string, unknown>>
      const plotFacts = (await this.loadPlotFacts()) as Record<string, unknown>

      for (const fact of facts) {
        if (fact.type === 'power' || fact.type === 'item' || fact.type === 'relation') {
          if (!charFacts[fact.subject]) {
            charFacts[fact.subject] = {}
          }
          const char: Record<string, unknown> = charFacts[fact.subject]

          if (fact.type === 'power' && fact.content) {
            const abilities = (char['abilities'] as string[]) || []
            if (!abilities.includes(fact.content)) {
              abilities.push(fact.content)
              char['abilities'] = abilities
            }
          }
          if (fact.type === 'relation' && fact.object) {
            const relationships = (char['relationships'] as Record<string, string>) || {}
            relationships[fact.object] = fact.content
            char['relationships'] = relationships
          }
          if (fact.type === 'item' && fact.content) {
            const items = (char['items'] as string[]) || []
            if (!items.includes(fact.content)) {
              items.push(fact.content)
              char['items'] = items
            }
          }
        }

        if (fact.type === 'foreshadow') {
          const foreshadowList = (plotFacts['伏笔清单'] as Array<Record<string, unknown>>) || []
          const existing = foreshadowList.some(
            p => p['description'] === fact.content && p['setup_chapter'] === fact.chapterStart
          )
          if (!existing) {
            foreshadowList.push({
              id: `F${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
              description: fact.content,
              setup_chapter: fact.chapterStart,
              status: '待回收',
              related_characters: fact.subject ? [fact.subject] : [],
            })
            plotFacts['伏笔清单'] = foreshadowList
          }
        }
      }

      const charWriteResult = await window.electronAPI.yaml.write(`${this.factsDir()}/characters_facts.yaml`, charFacts)
      if (!charWriteResult.success) {
        throw new Error(`角色事实保存失败: ${charWriteResult.error}`)
      }
      const plotWriteResult = await window.electronAPI.yaml.write(`${this.factsDir()}/plot_facts.yaml`, plotFacts)
      if (!plotWriteResult.success) {
        throw new Error(`情节事实保存失败: ${plotWriteResult.error}`)
      }

      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  }

  // ─── 读取 facts 用于 UI 显示 ─────────────────────────────────────────────

  async getFacts(
    filters?: {
      type?: string
      subject?: string
      chapter?: number
    },
    projectRootOverride?: string | null
  ): Promise<Fact[]> {
    const effectiveRoot = projectRootOverride ?? this.projectRoot
    if (!effectiveRoot) {
      throw new Error('未设置项目根路径，请先打开小说项目')
    }
    const factsDir = `${effectiveRoot}/facts`
    try {
      // 直接用 effectiveRoot 读取，不走 this.projectRoot（可能未同步）
      const charResult = await window.electronAPI.yaml.read(`${factsDir}/characters_facts.yaml`)
      const charFacts = (charResult.success && charResult.data
        ? charResult.data as Record<string, Record<string, unknown>>
        : {}) as Record<string, Record<string, unknown>>
      const plotResult = await window.electronAPI.yaml.read(`${factsDir}/plot_facts.yaml`)
      const plotFacts = (plotResult.success && plotResult.data
        ? plotResult.data as Record<string, unknown>
        : {}) as Record<string, unknown>

      const results: Fact[] = []

      // 从 characters_facts.yaml 还原 facts
      for (const [charName, char] of Object.entries(charFacts)) {
        if (char.abilities) {
          for (const ability of (char.abilities as string[]) || []) {
            results.push({
              id: `power-${charName}-${ability}`.slice(0, 64),
              type: 'power',
              subject: charName,
              object: '',
              content: ability,
              chapterStart: 1,
              chapterEnd: 9999,
              createdAt: 0,
            })
          }
        }
        if (char.relationships) {
          for (const [other, rel] of Object.entries(char.relationships as Record<string, string>)) {
            results.push({
              id: `rel-${charName}-${other}`.slice(0, 64),
              type: 'relation',
              subject: charName,
              object: other,
              content: rel,
              chapterStart: 1,
              chapterEnd: 9999,
              createdAt: 0,
            })
          }
        }
      }

      // 从 plot_facts.yaml 还原伏笔
      if (plotFacts['伏笔清单']) {
        for (const fb of (plotFacts['伏笔清单'] as Array<Record<string, unknown>>)) {
          results.push({
            id: fb['id'] ? `fb-${fb['id']}` : `fb-${Date.now()}`,
            type: 'foreshadow',
            subject: ((fb['related_characters'] as string[] || [])[0]) || '',
            object: '',
            content: String(fb['description'] || ''),
            chapterStart: Number(fb['setup_chapter'] || 1),
            chapterEnd: Number(fb['setup_chapter'] || 1),
            createdAt: 0,
          })
        }
      }

      // 过滤
      let filtered = results
      if (filters?.type && filters.type !== 'all') {
        filtered = filtered.filter(f => f.type === filters.type)
      }
      if (filters?.subject) {
        filtered = filtered.filter(
          f => f.subject === filters.subject || f.object === filters.subject
        )
      }
      if (filters?.chapter) {
        filtered = filtered.filter(
          f => f.chapterStart <= filters.chapter! && f.chapterEnd >= filters.chapter!
        )
      }

      return filtered
    } catch (e) {
      console.error('读取 facts 失败:', e)
      return []
    }
  }
}

const factsStore = new FactsStore()
export default factsStore

/**
 * AI 模型服务
 * 不同任务自动选择最合适的模型
 */

export type AIModel = 'doubao-pro' | 'doubao-lite' | 'doubao-mini' | 'deepseek-reasoner'
export type TaskType = 'creative' | 'summary' | 'classification' | 'logic' | 'extraction'

// 模型能力映射
const ModelTaskMapping: Record<TaskType, AIModel> = {
  creative: 'doubao-pro',         // 章节生成、创意续写
  summary: 'doubao-lite',         // 摘要、结构化分析
  classification: 'doubao-mini',  // 极速分类
  logic: 'deepseek-reasoner',     // 逻辑校验、一致性检查
  extraction: 'doubao-lite',      // 事实提取
}

// 模型配置
interface ModelConfig {
  maxTokens: number
  temperature: number
  topP: number
  presencePenalty: number
  frequencyPenalty: number
}

const ModelConfigs: Record<AIModel, ModelConfig> = {
  'doubao-pro': {
    maxTokens: 4096,
    temperature: 0.8,
    topP: 0.9,
    presencePenalty: 0.1,
    frequencyPenalty: 0.1,
  },
  'doubao-lite': {
    maxTokens: 2048,
    temperature: 0.3,
    topP: 0.85,
    presencePenalty: 0.0,
    frequencyPenalty: 0.0,
  },
  'doubao-mini': {
    maxTokens: 1024,
    temperature: 0.1,
    topP: 0.7,
    presencePenalty: 0.0,
    frequencyPenalty: 0.0,
  },
  'deepseek-reasoner': {
    maxTokens: 8192,
    temperature: 0.2,
    topP: 0.95,
    presencePenalty: 0.0,
    frequencyPenalty: 0.0,
  },
}

class AIModelService {
  /**
   * 根据任务类型选择最优模型
   */
  selectModel(taskType: TaskType): AIModel {
    return ModelTaskMapping[taskType] || 'doubao-pro'
  }

  /**
   * 获取模型配置
   */
  getModelConfig(model: AIModel): ModelConfig {
    return ModelConfigs[model] || ModelConfigs['doubao-pro']
  }

  /**
   * 调用 AI 模型 (非流式)
   */
  async call(
    taskType: TaskType,
    prompt: string,
    options?: Partial<ModelConfig> & { systemPrompt?: string }
  ): Promise<{ success: boolean; content?: string; error?: string }> {
    try {
      const model = this.selectModel(taskType)
      const config = { ...this.getModelConfig(model), ...options }

      const result = await window.electronAPI.ai.call(prompt, {
        model,
        ...config,
        systemPrompt: options?.systemPrompt,
      })

      return result
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error)
      return { success: false, error: msg }
    }
  }

  /**
   * 流式调用 AI 模型
   */
  async stream(
    taskType: TaskType,
    prompt: string,
    onChunk: (chunk: string, done: boolean) => void,
    onError?: (error: string) => void,
    options?: Partial<ModelConfig> & { systemPrompt?: string }
  ): Promise<void> {
    let removeChunkListener = () => {}
    let removeErrorListener = () => {}

    try {
      const model = this.selectModel(taskType)
      const config = { ...this.getModelConfig(model), ...options }

      // 监听流式输出
      removeChunkListener = window.electronAPI.ai.onStreamChunk((chunk) => {
        if (chunk.done) {
          onChunk('', true)
          removeChunkListener()
          removeErrorListener()
        } else {
          onChunk(chunk.content, false)
        }
      })

      // 监听错误
      removeErrorListener = window.electronAPI.ai.onStreamError((error) => {
        if (onError) onError(error)
        removeChunkListener()
        removeErrorListener()
      })

      // 发起流式请求
      await window.electronAPI.ai.stream(prompt, {
        model,
        ...config,
        systemPrompt: options?.systemPrompt,
      })
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error)
      if (onError) onError(msg)
    }
  }

  /**
   * 测试模型连接
   */
  async testConnection(model: AIModel): Promise<boolean> {
    try {
      const result = await window.electronAPI.ai.testConnection(model)
      if (!result || typeof result !== 'object') return false
      return !!(result.success && result.result)
    } catch {
      return false
    }
  }
}

// 单例导出
const aiModelService = new AIModelService()
export default aiModelService

/**
 * 事实提取服务
 * 自动从章节内容中提取战力、物品、关系、伏笔等事实
 */

import aiModelService from './aiModels'
import factsStore, { Fact } from '../db'

// 提取结果类型
export interface ExtractedFact extends Omit<Fact, 'id' | 'createdAt'> {
  confidence: number // 置信度 0-1
}

class FactExtractor {
  /**
   * 从章节内容提取事实
   */
  async extract(
    chapterContent: string,
    chapterNumber: number
  ): Promise<ExtractedFact[]> {
    try {
      const systemPrompt = `
你是小说事实提取专家。请从以下章节内容中提取关键事实信息，返回严格的JSON格式数组。

提取规则：
1. 战力信息(type="power")：角色的等级、实力、功法等
2. 物品信息(type="item")：武器、丹药、宝物等
3. 关系信息(type="relation")：角色之间的关系（朋友、敌人、师徒、夫妻等）
4. 伏笔信息(type="foreshadow")：后续可能用到的线索、未解开的谜团

每个事实必须包含：
- type: 类型（power/item/relation/foreshadow）
- subject: 主体（如"林枫"）
- object: 客体（可选，如"青云子"）
- content: 事实描述（如"林枫修炼到炼气三层"）
- chapterStart: 章节号（传入的 ${chapterNumber}）
- chapterEnd: 章节号（传入的 ${chapterNumber}）
- confidence: 置信度 0-1

返回格式示例：
[
  {
    "type": "power",
    "subject": "林枫",
    "object": "",
    "content": "林枫突破到炼气三层，实力提升三倍",
    "chapterStart": ${chapterNumber},
    "chapterEnd": ${chapterNumber},
    "confidence": 0.95
  }
]

只返回JSON，不要其他内容。
`

      const result = await aiModelService.call(
        'extraction',
        chapterContent,
        { systemPrompt }
      )

      if (!result.success || !result.content) {
        return []
      }

      // 解析提取结果
      let extractedFacts: ExtractedFact[]
      try {
        extractedFacts = JSON.parse(result.content.trim())
      } catch (parseError) {
        console.error('解析提取结果失败:', parseError)
        return []
      }

      // 结构验证：过滤掉字段不完整的事实
      const validTypes = ['power', 'item', 'relation', 'foreshadow']
      return extractedFacts.filter(f =>
        f && validTypes.includes(f.type)
        && f.subject && typeof f.content === 'string'
      )
    } catch (error) {
      console.error('事实提取失败:', error)
      return []
    }
  }

  /**
   * 批量保存事实到数据库
   */
  async saveFacts(facts: ExtractedFact[]): Promise<string[]> {
    const result = await factsStore.appendFacts(facts.map(f => ({
      type: f.type,
      subject: f.subject,
      object: f.object,
      content: f.content,
      chapterStart: f.chapterStart,
      chapterEnd: f.chapterEnd,
      confidence: f.confidence ?? 1.0,
    })))
    return result.success ? ['ok'] : []
  }

  /**
   * 自动提取并保存（用户确认后调用）
   */
  async extractAndSave(
    chapterContent: string,
    chapterNumber: number
  ): Promise<string[]> {
    const facts = await this.extract(chapterContent, chapterNumber)
    // 过滤置信度低于0.7的结果
    const highConfidenceFacts = facts.filter(f => f.confidence >= 0.7)
    return this.saveFacts(highConfidenceFacts)
  }

  /**
   * 验证事实一致性
   */
  async verifyConsistency(
    newFacts: ExtractedFact[],
    existingFacts: Fact[]
  ): Promise<Array<{ fact: ExtractedFact; conflict?: Fact; message: string }>> {
    const conflicts: Array<{ fact: ExtractedFact; conflict?: Fact; message: string }> = []

    for (const newFact of newFacts) {
      // 检查是否与现有事实冲突
      const conflicting = existingFacts.find(f => {
        if (f.subject !== newFact.subject) return false

        // 相同主体的战力信息冲突检查
        if (f.type === 'power' && newFact.type === 'power') {
          // 简单的冲突检测：如果新事实表明战力下降但没有合理解释
          const oldLevel = this.extractPowerLevel(f.content)
          const newLevel = this.extractPowerLevel(newFact.content)
          return oldLevel === null || newLevel === null ? false : newLevel < oldLevel
        }

        // 关系信息冲突检查
        if (f.type === 'relation' && newFact.type === 'relation') {
          return f.object === newFact.object && f.content !== newFact.content
        }

        return false
      })

      if (conflicting) {
        conflicts.push({
          fact: newFact,
          conflict: conflicting,
          message: `检测到事实冲突：现有记录 "${conflicting.content}" 与新提取的 "${newFact.content}" 不一致`
        })
      }
    }

    return conflicts
  }

  /**
   * 辅助方法：提取战力等级
   */
  private extractPowerLevel(content: string): number | null {
    const regex = /炼气(\d+)/
    const match = content.match(regex)
    if (match) return parseInt(match[1])

    const regex2 = /筑基(\d+)/i
    const match2 = content.match(regex2)
    if (match2 && match2[1]) return parseInt(match2[1], 10) + 10

    return null
  }
}

// 单例导出
const factExtractor = new FactExtractor()
export default factExtractor

import { useEffect, useRef, useState, forwardRef, useImperativeHandle } from 'react'
import * as monaco from 'monaco-editor'
import { Spin } from 'antd'
import { loader } from '@monaco-editor/react'

// 配置 Monaco Editor 加载路径
loader.config({
  paths: {
    vs: 'https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs'
  }
})

export interface EditorHandle {
  getSelectedText: () => string
  getCursorPosition: () => { lineNumber: number; column: number }
  insertText: (text: string) => void
  replaceSelection: (text: string) => void
}

interface EditorProps {
  value: string
  onChange: (value: string | undefined) => void
  filePath?: string
}

const Editor = forwardRef<EditorHandle, EditorProps>(({ value, onChange, filePath }, ref) => {
  const editorRef = useRef<HTMLDivElement>(null)
  const monacoEditorRef = useRef<monaco.editor.IStandaloneCodeEditor | null>(null)
  const [loading, setLoading] = useState(true)

  // 暴露编辑器方法给父组件
  useImperativeHandle(ref, () => ({
    getSelectedText: () => {
      if (!monacoEditorRef.current) return ''
      const selection = monacoEditorRef.current.getSelection()
      if (!selection) return ''
      return monacoEditorRef.current.getModel()?.getValueInRange(selection) || ''
    },
    getCursorPosition: () => {
      if (!monacoEditorRef.current) return { lineNumber: 1, column: 1 }
      const pos = monacoEditorRef.current.getPosition()
      return pos || { lineNumber: 1, column: 1 }
    },
    insertText: (text: string) => {
      if (!monacoEditorRef.current) return
      const position = monacoEditorRef.current.getPosition()
      if (position) {
        const range = new monaco.Range(
          position.lineNumber,
          position.column,
          position.lineNumber,
          position.column
        )
        monacoEditorRef.current.executeEdits('', [
          { range, text }
        ])
      }
    },
    replaceSelection: (text: string) => {
      if (!monacoEditorRef.current) return
      const selection = monacoEditorRef.current.getSelection()
      if (!selection) return
      monacoEditorRef.current.executeEdits('', [
        { range: selection, text }
      ])
    },
  }))

  // 初始化编辑器
  useEffect(() => {
    if (!editorRef.current) return

    let isMounted = true
    let debounceTimer: ReturnType<typeof setTimeout> | null = null
    const initEditor = async () => {
      try {
        // 加载 Monaco Editor
        await loader.init()

        if (!isMounted || !editorRef.current) return

        // 创建编辑器实例
        const editor = monaco.editor.create(editorRef.current, {
          value,
          language: 'markdown',
          theme: 'vs-light',
          fontSize: 16,
          lineHeight: 1.8,
          lineNumbers: 'on',
          wordWrap: 'on',
          wrappingIndent: 'indent',
          automaticLayout: true,
          minimap: { enabled: false },
          scrollBeyondLastLine: false,
          tabSize: 2,
          insertSpaces: true,
          renderWhitespace: 'none',
          renderLineHighlight: 'line',
          scrollbar: {
            verticalScrollbarSize: 10,
            horizontalScrollbarSize: 10,
          },
        })

        // 监听内容变化（带防抖，避免每次按键都触发父组件重渲染）
        editor.onDidChangeModelContent(() => {
          if (debounceTimer) clearTimeout(debounceTimer)
          debounceTimer = setTimeout(() => {
            if (!isMounted || !monacoEditorRef.current) return
            const newValue = editor.getValue()
            onChange(newValue)
          }, 300)
        })

        // 保存快捷键
        editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyS, () => {
          // 保存由 Workbench 处理
          const saveEvent = new KeyboardEvent('keydown', {
            key: 's',
            ctrlKey: true,
            bubbles: true
          })
          window.dispatchEvent(saveEvent)
        })

        monacoEditorRef.current = editor
        setLoading(false)
      } catch (error) {
        console.error('初始化编辑器失败:', error)
        setLoading(false)
      }
    }

    initEditor()

    return () => {
      isMounted = false
      if (debounceTimer) clearTimeout(debounceTimer)
      if (monacoEditorRef.current) {
        monacoEditorRef.current.dispose()
        monacoEditorRef.current = null
      }
    }
  }, [])

  // 当外部 value 变化时更新编辑器内容
  useEffect(() => {
    if (!monacoEditorRef.current) return

    const currentValue = monacoEditorRef.current.getValue()
    if (currentValue !== value) {
      // 使用 executeEdits 替代 setValue，保留 undo/redo 历史
      const model = monacoEditorRef.current.getModel()
      if (model) {
        monacoEditorRef.current.executeEdits('', [{
          range: model.getFullModelRange(),
          text: value,
        }])
      }
    }
  }, [value])

  // 根据文件类型切换语言模式
  useEffect(() => {
    if (!monacoEditorRef.current || !filePath) return

    const model = monacoEditorRef.current.getModel()
    if (!model) return

    if (filePath.endsWith('.md') || filePath.endsWith('.markdown')) {
      monaco.editor.setModelLanguage(model, 'markdown')
    } else if (filePath.endsWith('.yaml') || filePath.endsWith('.yml')) {
      monaco.editor.setModelLanguage(model, 'yaml')
    } else if (filePath.endsWith('.json')) {
      monaco.editor.setModelLanguage(model, 'json')
    }
  }, [filePath])

  if (loading) {
    return (
      <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <Spin tip="加载编辑器中..." />
      </div>
    )
  }

  return (
    <div ref={editorRef} style={{ width: '100%', height: '100%' }} />
  )
})

export default Editor

/**
 * 事实台账面板
 * 支持按类型/角色/章节筛选，伏笔状态管理，点击跳转章节
 * 新增伏笔看板视图
 */

import { useState, useEffect, useCallback, useMemo } from 'react'
import {
  List,
  Tag,
  Tabs,
  Empty,
  Spin,
  Button,
  message,
  Select,
  Input,
  Card,
  Badge,
  Space,
  Tooltip,
  Modal,
  Form,
  InputNumber,
  Switch,
  Alert,
  Row,
  Col,
} from 'antd'
import {
  ThunderboltOutlined,
  FireOutlined,
  GiftOutlined,
  TeamOutlined,
  BulbOutlined,
  ReloadOutlined,
  SearchOutlined,
  FilterOutlined,
  EyeOutlined,
  CheckOutlined,
  ExclamationCircleOutlined,
  DragOutlined,
} from '@ant-design/icons'
import factsStore, { Fact } from '../db'
import factExtractor from '../services/factExtractor'

const { TabPane } = Tabs

type FactType = 'all' | 'power' | 'item' | 'relation' | 'foreshadow'

const typeLabels: Record<FactType, { label: string; icon: React.ReactNode; color: string }> = {
  all: { label: '全部', icon: <ThunderboltOutlined />, color: 'default' },
  power: { label: '战力', icon: <FireOutlined />, color: 'red' },
  item: { label: '物品', icon: <GiftOutlined />, color: 'gold' },
  relation: { label: '关系', icon: <TeamOutlined />, color: 'blue' },
  foreshadow: { label: '伏笔', icon: <BulbOutlined />, color: 'purple' },
}

type ForeshadowStatus = '铺设中' | '待回收' | '已回收'

interface ForeshadowItem {
  id: string
  description: string
  setupChapter: number
  payoffChapter?: number
  status: ForeshadowStatus
  relatedCharacters: string[]
  type: '剧情伏笔' | '人物伏笔' | '世界观伏笔'
  isOverdue?: boolean // 超过10章未回收
}

interface FactsPanelProps {
  projectRoot?: string | null
}

const FactsPanel: React.FC<FactsPanelProps> = ({ projectRoot }) => {
  const [activeTab, setActiveTab] = useState<FactType | 'kanban'>('all')
  const [facts, setFacts] = useState<Fact[]>([])
  const [allFacts, setAllFacts] = useState<Fact[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [filterCharacter, setFilterCharacter] = useState<string>('')
  const [filterChapter, setFilterChapter] = useState<number | undefined>(undefined)
  const [showFilters, setShowFilters] = useState(false)
  const [characters, setCharacters] = useState<string[]>([])
  const [currentChapter, setCurrentChapter] = useState<number>(1)

  // 伏笔看板数据
  const [foreshadowItems, setForeshadowItems] = useState<ForeshadowItem[]>([])
  const [showAddForeshadow, setShowAddForeshadow] = useState(false)
  const [form] = Form.useForm()

  // 加载事实
  const loadFacts = async () => {
    setLoading(true)
    try {
      const result = await factsStore.getFacts(undefined, projectRoot)
      setAllFacts(result)

      // 提取所有角色名
      const charNames = Array.from(
        new Set(result.map(f => f.subject).filter(Boolean))
      ).sort() as string[]
      setCharacters(charNames)

      setAllFacts(result)
      applyFilters(result)

      // 加载伏笔看板（setAllFacts 同步完成，loadForeshadowKanban 读取的是最新 state）
      if (projectRoot) {
        setTimeout(() => loadForeshadowKanban(result), 0)
      }
    } catch (error) {
      message.error('加载事实失败')
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  // 加载伏笔看板
  const loadForeshadowKanban = async (facts?: Fact[]) => {
    if (!projectRoot) return
    const allFactsData = facts || allFacts
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []

        // 获取当前最大章节数（用于判断超期）
        const chapters = allFactsData
          .map((f: Fact) => Math.max(f.chapterStart, f.chapterEnd))
          .filter((c: number) => c < 9999)
        const currentMaxChapter = chapters.length > 0 ? Math.max(...chapters) : currentChapter

        const items: ForeshadowItem[] = foreshadowList.map((fb, idx) => {
          const setupChapter = Number(fb['setup_chapter'] || 1)
          const payoffChapter = fb['payoff_chapter'] ? Number(fb['payoff_chapter']) : undefined
          const status = (fb['status'] as ForeshadowStatus) || '待回收'
          const isOverdue = !!(status !== '已回收' && !payoffChapter && currentMaxChapter >= setupChapter && (currentMaxChapter - setupChapter) > 10)

          return {
            id: String(fb['id'] || `fs-${idx}`),
            description: String(fb['description'] || ''),
            setupChapter,
            payoffChapter,
            status,
            relatedCharacters: (fb['related_characters'] as string[]) || [],
            type: (fb['type'] as ForeshadowItem['type']) || '剧情伏笔',
            isOverdue,
          }
        })

        setForeshadowItems(items)
      }
    } catch (error) {
      console.warn('加载伏笔看板失败:', error)
    }
  }

  // 获取当前最大章节数
  const getCurrentMaxChapter = (): number => {
    // 从 facts 中获取最大的章节号
    const chapters = allFacts
      .map(f => Math.max(f.chapterStart, f.chapterEnd))
      .filter(c => c < 9999)
    return chapters.length > 0 ? Math.max(...chapters) : currentChapter
  }

  // 更新伏笔状态
  const handleUpdateForeshadowStatus = async (
    item: ForeshadowItem,
    newStatus: ForeshadowStatus
  ) => {
    if (!projectRoot) return
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
        const updated = foreshadowList.map(fb => {
          if (fb['id'] === item.id) {
            return { ...fb, status: newStatus }
          }
          return fb
        })
        plotData['伏笔清单'] = updated
        const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
        if (!writeResult.success) {
          message.error(`保存失败: ${writeResult.error}`)
          return
        }
        message.success(`伏笔状态已更新为「${newStatus}」`)
        await loadForeshadowKanban()
      }
    } catch (error) {
      message.error('更新失败')
    }
  }

  // 添加伏笔
  const handleAddForeshadow = async () => {
    if (!projectRoot) return
    try {
      const values = await form.validateFields()
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []

        foreshadowList.push({
          id: `FS${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
          description: values.description,
          setup_chapter: values.setupChapter || 1,
          payoff_chapter: values.payoffChapter || undefined,
          status: '铺设中',
          related_characters: values.relatedCharacters || [],
          type: values.type || '剧情伏笔',
        })

        plotData['伏笔清单'] = foreshadowList
        const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
        if (!writeResult.success) {
          message.error(`保存失败: ${writeResult.error}`)
          return
        }
        message.success('伏笔已添加')
        setShowAddForeshadow(false)
        form.resetFields()
        await loadForeshadowKanban()
      }
    } catch (error) {
      message.error('添加失败')
    }
  }

  // 删除伏笔
  const handleDeleteForeshadow = async (item: ForeshadowItem) => {
    if (!projectRoot) return
    Modal.confirm({
      title: '确认删除此伏笔？',
      content: item.description,
      okText: '确认删除',
      okType: 'danger',
      onOk: async () => {
        try {
          const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
          const result = await window.electronAPI.yaml.read(plotFactsFile)
          if (result.success && result.data) {
            const plotData = result.data as Record<string, unknown>
            const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
            const filtered = foreshadowList.filter(fb => fb['id'] !== item.id)
            plotData['伏笔清单'] = filtered
            const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
            if (!writeResult.success) {
              message.error(`保存失败: ${writeResult.error}`)
              return
            }
            message.success('伏笔已删除')
            await loadForeshadowKanban()
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // 提取当前章节事实
  const extractCurrentChapter = async () => {
    message.info('请在编辑器中选择章节后，使用右侧「AI工具 → 提取事实」功能')
  }

  // 应用筛选
  const applyFilters = useCallback((source: Fact[]) => {
    let filtered = source

    if (activeTab !== 'all') {
      filtered = filtered.filter(f => f.type === activeTab)
    }

    if (searchText) {
      const search = searchText.toLowerCase()
      filtered = filtered.filter(
        f =>
          f.subject.toLowerCase().includes(search) ||
          f.object?.toLowerCase().includes(search) ||
          f.content.toLowerCase().includes(search)
      )
    }

    if (filterCharacter) {
      filtered = filtered.filter(
        f => f.subject === filterCharacter || f.object === filterCharacter
      )
    }

    if (filterChapter) {
      filtered = filtered.filter(
        f => f.chapterStart <= filterChapter! && f.chapterEnd >= filterChapter!
      )
    }

    setFacts(filtered)
  }, [activeTab, searchText, filterCharacter, filterChapter])

  // 标签切换时重新筛选
  useEffect(() => {
    if (activeTab !== 'kanban') {
      applyFilters(allFacts)
    }
  }, [activeTab, searchText, filterCharacter, filterChapter, allFacts, applyFilters])

  // 切换标签时重新加载
  useEffect(() => {
    loadFacts()
  }, [projectRoot])

  // 格式化事实项
  const renderFactItem = (item: Fact) => {
    const typeInfo = typeLabels[item.type as FactType]
    const isForeshadow = item.type === 'foreshadow'

    return (
      <List.Item
        key={item.id}
        style={{ cursor: 'pointer' }}
      >
        <List.Item.Meta
          title={
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
              <Tag color={typeInfo.color}>
                {typeInfo.icon} {typeInfo.label}
              </Tag>
              <strong>{item.subject}</strong>
              {item.object && (
                <>
                  <span style={{ color: '#999' }}>→</span>
                  <strong>{item.object}</strong>
                </>
              )}
              {isForeshadow && (
                <Tag
                  color={
                    item.content.includes('已回收')
                      ? 'green'
                      : item.content.includes('铺设中')
                        ? 'blue'
                        : 'orange'
                  }
                  style={{ marginLeft: 4 }}
                >
                  {item.content.includes('已回收') ? '已回收' : item.content.includes('铺设中') ? '铺设中' : '待回收'}
                </Tag>
              )}
            </div>
          }
          description={
            <div>
              <p style={{ margin: '4px 0' }}>{item.content}</p>
              <div
                style={{
                  fontSize: 12,
                  color: '#999',
                  marginTop: 4,
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                }}
              >
                <span>
                  第 {item.chapterStart} 章
                  {item.chapterEnd !== item.chapterStart && ` - 第 ${item.chapterEnd} 章`}
                </span>
              </div>
            </div>
          }
        />
      </List.Item>
    )
  }

  // 伏笔看板卡片
  const renderForeshadowCard = (item: ForeshadowItem) => {
    const isOverdue = item.isOverdue

    return (
      <Card
        key={item.id}
        size="small"
        style={{
          marginBottom: 8,
          borderColor: isOverdue ? '#ff4d4f' : undefined,
          borderWidth: isOverdue ? 2 : 1,
        }}
        bodyStyle={{ padding: 10 }}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div style={{ flex: 1 }}>
            {isOverdue && (
              <Tag color="red" icon={<ExclamationCircleOutlined />} style={{ marginBottom: 4 }}>
                超期未回收
              </Tag>
            )}
            <div style={{ fontSize: 13, marginBottom: 6 }}>{item.description}</div>
            <div style={{ fontSize: 11, color: '#999' }}>
              <span>铺设：第{item.setupChapter}章</span>
              {item.payoffChapter && (
                <span> → 回收：第{item.payoffChapter}章</span>
              )}
            </div>
            {item.relatedCharacters.length > 0 && (
              <div style={{ marginTop: 4 }}>
                {item.relatedCharacters.slice(0, 3).map(char => (
                  <Tag key={char} color="blue" style={{ fontSize: 10 }}>
                    {char}
                  </Tag>
                ))}
                {item.relatedCharacters.length > 3 && (
                  <Tag style={{ fontSize: 10 }}>+{item.relatedCharacters.length - 3}</Tag>
                )}
              </div>
            )}
          </div>
          <Button
            type="text"
            size="small"
            danger
            icon={<CheckOutlined />}
            onClick={(e) => {
              e.stopPropagation()
              handleDeleteForeshadow(item)
            }}
            style={{ marginLeft: 4 }}
          />
        </div>
      </Card>
    )
  }

  // 伏笔看板三列
  const renderForeshadowKanban = () => {
    const columns: { status: ForeshadowStatus; color: string; items: ForeshadowItem[] }[] = [
      { status: '铺设中', color: 'blue', items: foreshadowItems.filter(f => f.status === '铺设中') },
      { status: '待回收', color: 'orange', items: foreshadowItems.filter(f => f.status === '待回收') },
      { status: '已回收', color: 'green', items: foreshadowItems.filter(f => f.status === '已回收') },
    ]

    const overdueCount = foreshadowItems.filter(f => f.isOverdue).length

    return (
      <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
        <div style={{ padding: '8px 16px', borderBottom: '1px solid #e8e8e8' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
            <Space>
              <span style={{ fontWeight: 500 }}>伏笔看板</span>
              <Badge count={foreshadowItems.length} style={{ fontSize: 10 }} />
            </Space>
            <Button
              size="small"
              type="primary"
              icon={<BulbOutlined />}
              onClick={() => setShowAddForeshadow(true)}
            >
              添加伏笔
            </Button>
          </div>
          {overdueCount > 0 && (
            <Alert
              message={`有 ${overdueCount} 个伏笔超过10章未回收（已标红）`}
              type="warning"
              showIcon
              style={{ fontSize: 11, marginBottom: 8 }}
            />
          )}
        </div>

        <div style={{ flex: 1, overflow: 'auto', padding: 12 }}>
          <Row gutter={8}>
            {columns.map(col => (
              <Col key={col.status} span={8}>
                <div
                  style={{
                    background: '#f5f5f5',
                    borderRadius: 8,
                    padding: 8,
                    minHeight: 300,
                  }}
                >
                  <div style={{
                    textAlign: 'center',
                    marginBottom: 8,
                    fontWeight: 500,
                    color: col.color,
                  }}>
                    {col.status}
                    <Badge
                      count={col.items.length}
                      style={{ marginLeft: 6 }}
                      color={col.color}
                    />
                  </div>

                  {col.items.length === 0 ? (
                    <div style={{ textAlign: 'center', color: '#999', padding: 20, fontSize: 12 }}>
                      暂无伏笔
                    </div>
                  ) : (
                    <div>
                      {col.items.map(item => (
                        <div
                          key={item.id}
                          style={{ position: 'relative' }}
                          onClick={() => {
                            if (col.status !== '已回收') {
                              const nextStatus: ForeshadowStatus =
                                col.status === '铺设中' ? '待回收' : '已回收'
                              handleUpdateForeshadowStatus(item, nextStatus)
                            }
                          }}
                        >
                          {renderForeshadowCard(item)}
                          {col.status !== '已回收' && (
                            <div style={{
                              position: 'absolute',
                              bottom: -4,
                              left: '50%',
                              transform: 'translateX(-50%)',
                              fontSize: 10,
                              color: '#999',
                              cursor: 'pointer',
                            }}>
                              ↓ 点击推进
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </Col>
            ))}
          </Row>
        </div>

        {/* 添加伏笔 Modal */}
        <Modal
          title="添加伏笔"
          open={showAddForeshadow}
          onCancel={() => setShowAddForeshadow(false)}
          onOk={handleAddForeshadow}
          okText="添加"
        >
          <Form form={form} layout="vertical">
            <Form.Item
              name="description"
              label="伏笔描述"
              rules={[{ required: true, message: '请输入伏笔描述' }]}
            >
              <Input.TextArea rows={2} placeholder="描述这个伏笔的内容..." />
            </Form.Item>
            <Form.Item name="setupChapter" label="铺设章节" initialValue={1}>
              <InputNumber min={1} style={{ width: '100%' }} />
            </Form.Item>
            <Form.Item name="payoffChapter" label="计划回收章节">
              <InputNumber min={1} placeholder="留空表示未计划" style={{ width: '100%' }} />
            </Form.Item>
            <Form.Item name="type" label="伏笔类型" initialValue="剧情伏笔">
              <Select
                options={[
                  { value: '剧情伏笔', label: '剧情伏笔' },
                  { value: '人物伏笔', label: '人物伏笔' },
                  { value: '世界观伏笔', label: '世界观伏笔' },
                ]}
              />
            </Form.Item>
            <Form.Item name="relatedCharacters" label="关联角色">
              <Select
                mode="tags"
                placeholder="输入角色名（回车确认）"
                options={characters.map(c => ({ value: c, label: c }))}
              />
            </Form.Item>
          </Form>
        </Modal>
      </div>
    )
  }

  // 统计摘要
  const stats = useMemo(() => ({
    total: allFacts.length,
    power: allFacts.filter(f => f.type === 'power').length,
    item: allFacts.filter(f => f.type === 'item').length,
    relation: allFacts.filter(f => f.type === 'relation').length,
    foreshadow: foreshadowItems.length,
    foreshadowPending: foreshadowItems.filter(f => f.status === '待回收').length,
    foreshadowOverdue: foreshadowItems.filter(f => f.isOverdue).length,
  }), [allFacts, foreshadowItems])

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '10px 16px', borderBottom: '1px solid #e8e8e8' }}>
        {/* 统计栏 */}
        <div
          style={{
            display: 'flex',
            gap: 8,
            marginBottom: 10,
            flexWrap: 'wrap',
            fontSize: 12,
          }}
        >
          <Badge count={stats.total} showZero color="#1890ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>全部</span>
          </Badge>
          <Badge count={stats.power} showZero color="#ff4d4f" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>战力</span>
          </Badge>
          <Badge count={stats.relation} showZero color="#1677ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>关系</span>
          </Badge>
          <Badge count={stats.foreshadow} showZero color="#722ed1" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>
              伏笔
              {stats.foreshadowPending > 0 && ` (${stats.foreshadowPending}待收)`}
            </span>
          </Badge>
          {stats.foreshadowOverdue > 0 && (
            <Badge count={stats.foreshadowOverdue} showZero color="#ff4d4f" style={{ fontSize: 11 }}>
              <span style={{ padding: '2px 8px', background: '#fff1f0', borderRadius: 4, color: '#ff4d4f' }}>
                超期
              </span>
            </Badge>
          )}
        </div>

        {/* 搜索和筛选 */}
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 10 }}>
          <Input
            placeholder="搜索事实..."
            prefix={<SearchOutlined />}
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            allowClear
            size="small"
            style={{ flex: 1 }}
          />
          <Button
            size="small"
            icon={<FilterOutlined />}
            onClick={() => setShowFilters(!showFilters)}
            type={showFilters ? 'primary' : 'default'}
          >
            筛选
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={loadFacts}
          />
        </div>

        {/* 高级筛选 */}
        {showFilters && (
          <div style={{ marginBottom: 10, padding: 8, background: '#f5f5f5', borderRadius: 6 }}>
            <Space direction="vertical" style={{ width: '100%' }}>
              <Select
                placeholder="按角色筛选"
                value={filterCharacter || undefined}
                onChange={(val) => setFilterCharacter(val || '')}
                options={characters.map(c => ({ value: c, label: c }))}
                style={{ width: '100%' }}
                size="small"
                allowClear
                showSearch
              />
              <InputNumber
                placeholder="按章节筛选"
                value={filterChapter}
                onChange={(val) => setFilterChapter(val ?? undefined)}
                min={1}
                style={{ width: '100%' }}
                size="small"
              />
              <Button
                size="small"
                onClick={() => {
                  setFilterCharacter('')
                  setFilterChapter(undefined)
                }}
              >
                清除筛选
              </Button>
            </Space>
          </div>
        )}

        <Tabs
          activeKey={activeTab}
          onChange={(key) => setActiveTab(key as FactType | 'kanban')}
          size="small"
        >
          {Object.entries(typeLabels).map(([key, info]) => (
            <TabPane
              key={key}
